const storage = {
  get(key) {
    try {
      return window.localStorage.getItem(key);
    } catch {
      return null;
    }
  },
  set(key, value) {
    try {
      window.localStorage.setItem(key, value);
    } catch {
      // The page should keep working even when storage is unavailable.
    }
  },
};

function readCache(key) {
  try {
    const cached = storage.get(key);
    if (!cached) {
      return null;
    }

    const parsed = JSON.parse(cached);
    if (!parsed || typeof parsed.time !== "number") {
      return null;
    }

    return parsed;
  } catch {
    return null;
  }
}

function writeCache(key, value) {
  storage.set(key, JSON.stringify({ time: Date.now(), value }));
}

function isFreshCache(cacheEntry, ttl) {
  if (!cacheEntry) {
    return false;
  }

  const age = Date.now() - cacheEntry.time;
  return age >= 0 && age < ttl;
}

