let activeThought = null;
let reflectionCanonicalEntries = [];
let reflectionEntries = [];
let reflectionIndex = 0;
let reflectionPlaybackMode = "random";
let reflectionTimer = 0;
let reflectionDeadline = 0;
let reflectionRemaining = REFLECTION_INTERVAL;
let reflectionManualPause = false;
let reflectionReady = false;
let reflectionMeasure = null;
let reflectionResizeObserver = null;
let reflectionVisibilityObserver = null;
let reflectionResizeFrame = 0;
let reflectionStageWidth = 0;
const reflectionPauseReasons = new Set();
let activeProjects = BUNDLED_PROJECTS;
let projectsLoadState = "fallback";
let projectsExpanded = false;
let currentProjectSort = projectSortSelect?.value === "recent" ? "recent" : "popular";
let blogThoughtRequestId = 0;
let githubProjectsRequestId = 0;
