let githubProjectsController = null;
let siteContentRequestId = 0;
let siteContentController = null;

function getStoredLanguage() {
  const language = storage.get("language");
  return i18n[language] ? language : "zh";
}

function getStoredTheme() {
  const theme = storage.get("theme");
  return ["dark", "light"].includes(theme) ? theme : "light";
}

let currentLanguage = getStoredLanguage();
let currentTheme = getStoredTheme();

async function refreshPageState() {
  currentLanguage = getStoredLanguage();
  currentTheme = getStoredTheme();
  projectsExpanded = false;
  applyTheme(currentTheme);
  applyLanguage(currentLanguage);
  await loadSiteContent();
  applyLanguage(currentLanguage);
  loadBlogThought();
  loadGithubProjects();
}

function setMeta(name, value, property = false) {
  const selector = property ? `meta[property="${name}"]` : `meta[name="${name}"]`;
  const meta = document.querySelector(selector);
  if (meta) {
    meta.setAttribute("content", value);
  }
}

function applyTheme(theme) {
  currentTheme = theme;
  root.dataset.theme = theme;
  body.dataset.theme = theme;
  storage.set("theme", theme);

  const dict = i18n[currentLanguage];
  const isDark = theme === "dark";
  const icon = document.querySelector("[data-theme-icon]");
  const label = document.querySelector("[data-theme-label]");

  if (icon) {
    icon.textContent = isDark ? "☀" : "☾";
  }

  if (label) {
    label.textContent = isDark ? dict.theme_light : dict.theme_dark;
  }

  if (themeToggle) {
    themeToggle.setAttribute("aria-label", isDark ? dict.theme_to_light : dict.theme_to_dark);
  }

  setMeta("theme-color", isDark ? "#080a0d" : "#fafbfc");
}

function applyThemeWithTransition(theme) {
  if (!motionAllowed || typeof document.startViewTransition !== "function") {
    applyTheme(theme);
    return;
  }

  const transition = document.startViewTransition(() => applyTheme(theme));
  transition.finished.catch(() => {
    // Rapid repeated toggles may supersede an in-flight visual transition.
  });
}

function applyLanguage(language) {
  currentLanguage = i18n[language] ? language : "zh";
  const dict = i18n[currentLanguage];

  root.lang = currentLanguage === "zh" ? "zh-CN" : "en";
  document.title = dict.document_title;
  storage.set("language", currentLanguage);

  document.querySelectorAll("[data-i18n]").forEach((element) => {
    const key = element.dataset.i18n;
    if (dict[key]) {
      element.textContent = dict[key];
    }
  });

  document.querySelectorAll("[data-i18n-attr]").forEach((element) => {
    element.dataset.i18nAttr.split(",").forEach((pair) => {
      const [attr, key] = pair.split(":").map((part) => part.trim());
      if (attr && key && dict[key]) {
        element.setAttribute(attr, dict[key]);
      }
    });
  });

  const langLabel = document.querySelector("[data-lang-label]");
  if (langLabel) {
    langLabel.textContent = dict.language_label;
  }

  if (languageToggle) {
    languageToggle.setAttribute("aria-label", dict.language_aria);
  }

  if (projectSortSelect) {
    projectSortSelect.value = currentProjectSort;
  }

  if (thoughtLink) {
    thoughtLink.setAttribute("aria-label", dict.thought_link);
  }

  if (reflectionReady) {
    setReflectionArchive(dict.hero_lead);
  }

  if (activeThought) {
    renderThought(activeThought);
  }

  if (activeProjects.length > 0 || projectsLoadState !== "idle") {
    renderGithubProjects(activeProjects, projectsLoadState);
  }

  const shieldTitle = document.querySelector(".devtools-shield strong");
  const shieldText = document.querySelector(".devtools-shield span");
  if (shieldTitle) {
    shieldTitle.textContent = dict.devtools_title;
  }
  if (shieldText) {
    shieldText.textContent = dict.devtools_text;
  }

  setMeta("description", dict.meta_description);
  setMeta("og:title", dict.document_title, true);
  setMeta("og:description", dict.og_description, true);
  setMeta("og:locale", dict.og_locale, true);
  setMeta("og:image:alt", dict.social_image_alt, true);
  setMeta("twitter:title", dict.document_title);
  setMeta("twitter:description", dict.og_description);
  setMeta("twitter:image:alt", dict.social_image_alt);
  applyTheme(currentTheme);
}

function isValidReflectionDate(value) {
  if (!REFLECTION_DATE_PATTERN.test(value)) {
    return false;
  }
  const [yearValue, monthValue, dayValue] = value.split("-").map(Number);
  const date = new Date(Date.UTC(yearValue, monthValue - 1, dayValue));
  return !Number.isNaN(date.getTime()) && date.toISOString().slice(0, 10) === value;
}

function parseReflectionArchive(value) {
  if (typeof value !== "string" || reflectionTextLength(value) > CONTENT_MAX_TEXT_LENGTH) {
    return [];
  }

  const entries = [];
  const lines = value.replace(/\r\n?/g, "\n").split("\n");
  let current = null;
  let sourceOrder = 0;

  const commit = () => {
    if (!current) {
      return true;
    }
    const text = current.lines.join("\n").trim().replace(/\n{3,}/g, "\n\n");
    if (!text || reflectionTextLength(text) > REFLECTION_MAX_LENGTH || entries.length >= REFLECTION_MAX_ITEMS) {
      return false;
    }
    entries.push({
      source: current.source,
      date: current.date,
      title: current.title,
      text,
      sourceOrder: current.sourceOrder,
    });
    current = null;
    return true;
  };

  for (const line of lines) {
    const trimmed = line.trim();
    const momentHeader = REFLECTION_DATE_PATTERN.test(trimmed);
    const labeledHeader = trimmed.match(REFLECTION_ICLOUD_HEADER_PATTERN);
    if (momentHeader || labeledHeader) {
      if (!commit()) {
        return [];
      }
      if (labeledHeader) {
        const date = labeledHeader[1];
        if (!isValidReflectionDate(date)) {
          return [];
        }
        current = {
          source: "icloud",
          date,
          title: labeledHeader[2].trim(),
          lines: [],
          sourceOrder,
        };
      } else {
        if (!isValidReflectionDate(trimmed)) {
          return [];
        }
        current = { source: "moments", date: trimmed, title: "", lines: [], sourceOrder };
      }
      sourceOrder += 1;
    } else if (trimmed.startsWith("@")) {
      return [];
    } else if (current) {
      current.lines.push(line.trimEnd());
    } else if (trimmed) {
      return [];
    }
  }
  if (!commit()) {
    return [];
  }

  return entries;
}

function sortReflectionEntries(entries) {
  return [...entries].sort((left, right) => {
    if (left.date && right.date && left.date !== right.date) {
      return right.date.localeCompare(left.date);
    }
    if (left.date && !right.date) {
      return -1;
    }
    if (!left.date && right.date) {
      return 1;
    }
    return left.sourceOrder - right.sourceOrder;
  });
}

function shuffleReflectionEntries(entries, avoidFirst = null) {
  const shuffled = [...entries];
  for (let index = shuffled.length - 1; index > 0; index -= 1) {
    const swapIndex = Math.floor(Math.random() * (index + 1));
    [shuffled[index], shuffled[swapIndex]] = [shuffled[swapIndex], shuffled[index]];
  }
  if (avoidFirst && shuffled.length > 1 && shuffled[0] === avoidFirst) {
    const swapIndex = shuffled.findIndex((entry) => entry !== avoidFirst);
    [shuffled[0], shuffled[swapIndex]] = [shuffled[swapIndex], shuffled[0]];
  }
  return shuffled;
}

function buildReflectionPlayback(entries, avoidFirst = null) {
  return reflectionPlaybackMode === "random"
    ? shuffleReflectionEntries(entries, avoidFirst)
    : [...entries];
}

function isValidManagedReflectionArchive(entries, language) {
  if (!Array.isArray(entries) || entries.length !== 100) {
    return false;
  }
  const moments = entries.filter((entry) => entry.source === "moments").length;
  const icloud = entries.filter((entry) => entry.source === "icloud").length;
  if (moments !== 31 || icloud !== 69 || entries.some((entry) => !isValidReflectionDate(entry.date))) {
    return false;
  }
  return language !== "en"
    || entries.every((entry) => !REFLECTION_HAN_PATTERN.test(`${entry.title}\n${entry.text}`));
}

function haveMatchingReflectionOrder(chineseEntries, englishEntries) {
  return chineseEntries.length === englishEntries.length
    && chineseEntries.every((entry, index) => {
      const counterpart = englishEntries[index];
      return entry.source === counterpart.source && entry.date === counterpart.date;
    });
}

function formatReflectionDate(value) {
  return value ? value.replaceAll("-", ".") : "";
}

function formatReflectionSource(value) {
  const dict = i18n[currentLanguage];
  return value === "icloud" ? dict.reflections_source_icloud : dict.reflections_source_moments;
}

function reflectionTextLength(value) {
  return Array.from(value).length;
}

function normalizeReflectionPreviewText(value) {
  return value
    .replace(/\r\n?/g, "\n")
    .split("\n")
    .map((line) => line.trim())
    .join("\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function getReflectionSentenceBreaks(value, language) {
  if (typeof Intl.Segmenter === "function") {
    try {
      const locale = language === "zh" ? "zh-CN" : "en";
      const segmenter = new Intl.Segmenter(locale, { granularity: "sentence" });
      let offset = 0;
      return Array.from(segmenter.segment(value), ({ segment }) => {
        offset += reflectionTextLength(segment);
        return offset;
      });
    } catch {
      // The regex fallback below keeps previews usable in older browsers.
    }
  }

  const characters = Array.from(value);
  const breaks = [];
  characters.forEach((character, index) => {
    if (/[。！？!?…]/u.test(character)) {
      breaks.push(index + 1);
    }
  });
  return breaks;
}

function getReflectionMeasure() {
  if (reflectionMeasure?.isConnected) {
    return reflectionMeasure;
  }

  reflectionMeasure = document.createElement("p");
  reflectionMeasure.className = "reflection-preview-measure";
  reflectionMeasure.setAttribute("aria-hidden", "true");
  body.append(reflectionMeasure);
  return reflectionMeasure;
}

function measureReflectionLines(value, density) {
  const measure = getReflectionMeasure();
  const availableWidth = reflectionStage?.getBoundingClientRect().width
    || reflectionPreview?.getBoundingClientRect().width
    || 360;
  measure.dataset.reflectionDensity = density;
  measure.lang = currentLanguage === "zh" ? "zh-CN" : "en";
  measure.style.width = `${Math.max(240, availableWidth)}px`;
  measure.textContent = value;

  const lineHeight = Number.parseFloat(window.getComputedStyle(measure).lineHeight);
  if (!Number.isFinite(lineHeight) || lineHeight <= 0) {
    return REFLECTION_PREVIEW_MAX_LINES + 1;
  }
  return Math.max(1, Math.ceil((measure.scrollHeight - 0.5) / lineHeight));
}

function findReflectionSemanticBreak(value, maximum, language) {
  const characters = Array.from(value);
  const minimumSentence = Math.floor(maximum * 0.52);
  const sentenceBreaks = getReflectionSentenceBreaks(value, language)
    .filter((position) => position >= minimumSentence && position <= maximum);
  const sentenceBreak = sentenceBreaks[sentenceBreaks.length - 1];
  if (sentenceBreak) {
    return sentenceBreak;
  }

  const minimumClause = Math.floor(maximum * 0.62);
  let clauseBreak = 0;
  for (let index = minimumClause; index < maximum; index += 1) {
    const character = characters[index];
    if (character === "\n" || /[；;：:，,—–]/u.test(character)) {
      clauseBreak = index + 1;
    }
  }
  if (clauseBreak) {
    return clauseBreak;
  }

  if (language === "en") {
    const minimumWord = Math.floor(maximum * 0.72);
    for (let index = maximum - 1; index >= minimumWord; index -= 1) {
      if (/\s/u.test(characters[index])) {
        return index;
      }
    }
  }
  return maximum;
}

function fitReflectionPreview(value, density, language) {
  const characters = Array.from(value);
  let low = 1;
  let high = characters.length - 1;
  let maximum = 1;

  while (low <= high) {
    const middle = Math.floor((low + high) / 2);
    const candidate = `${characters.slice(0, middle).join("").trim()}…`;
    if (measureReflectionLines(candidate, density) <= REFLECTION_PREVIEW_MAX_LINES) {
      maximum = middle;
      low = middle + 1;
    } else {
      high = middle - 1;
    }
  }

  const cutAt = findReflectionSemanticBreak(value, maximum, language);
  const prefix = characters.slice(0, cutAt).join("").trimEnd();
  const endsAtSentence = /[。！？.!?…][”’」』】）)]?$/u.test(prefix);
  let preview = endsAtSentence
    ? prefix
    : `${prefix.replace(/[，,；;：:\s]+$/u, "")}…`;

  while (reflectionTextLength(preview) > 1 && measureReflectionLines(preview, density) > REFLECTION_PREVIEW_MAX_LINES) {
    preview = `${Array.from(preview.replace(/…$/u, "")).slice(0, -1).join("").trimEnd()}…`;
  }
  return preview;
}

function getReflectionReadingMinutes(value, language) {
  if (language === "zh") {
    return Math.max(1, Math.ceil(reflectionTextLength(value.replace(/\s+/g, "")) / 400));
  }
  const words = value.trim().match(/[\p{L}\p{N}]+(?:['’\-][\p{L}\p{N}]+)*/gu)?.length || 1;
  return Math.max(1, Math.ceil(words / 220));
}

function buildReflectionPreview(value, language = currentLanguage) {
  const normalized = normalizeReflectionPreviewText(value);
  const readingMinutes = getReflectionReadingMinutes(normalized, language);

  if (measureReflectionLines(normalized, "short") <= REFLECTION_SHORT_MAX_LINES) {
    return {
      text: normalized,
      density: "short",
      truncated: false,
      readingMinutes,
    };
  }

  if (measureReflectionLines(normalized, "medium") <= REFLECTION_PREVIEW_MAX_LINES) {
    return {
      text: normalized,
      density: "medium",
      truncated: false,
      readingMinutes,
    };
  }

  return {
    text: fitReflectionPreview(normalized, "long", language),
    density: "long",
    truncated: true,
    readingMinutes,
  };
}

function formatReflectionReadAction(minutes, compact = window.matchMedia("(max-width: 460px)").matches) {
  const dict = i18n[currentLanguage];
  const durationTemplate = compact ? dict.reflections_read_time_compact : dict.reflections_read_time;
  const duration = durationTemplate.replace("{minutes}", String(minutes));
  const action = compact ? dict.reflections_more_compact : dict.reflections_more;
  return `${action} · ${duration}`;
}

function clearReflectionTimer() {
  if (reflectionTimer) {
    window.clearTimeout(reflectionTimer);
    reflectionTimer = 0;
  }
}

function syncReflectionFocusReason() {
  if (!reflectionRotator) {
    return;
  }
  const focusInside = reflectionRotator.contains(document.activeElement);
  const focusWasPaused = reflectionPauseReasons.has("focus");
  if (focusInside) {
    reflectionPauseReasons.add("focus");
  } else {
    reflectionPauseReasons.delete("focus");
  }
  if (focusInside !== focusWasPaused) {
    updateReflectionPauseUI();
  }
}

function updateReflectionPauseUI() {
  if (!reflectionRotator || !reflectionStage || !reflectionToggle || !reflectionToggleLabel) {
    return;
  }
  const paused = reflectionPauseReasons.size > 0;
  const dict = i18n[currentLanguage];
  reflectionRotator.classList.toggle("is-paused", paused);
  reflectionStage.setAttribute("aria-live", paused ? "polite" : "off");
  reflectionToggleLabel.textContent = reflectionManualPause ? dict.reflections_resume : dict.reflections_pause;
  reflectionToggle.setAttribute(
    "aria-label",
    reflectionManualPause ? dict.reflections_resume_aria : dict.reflections_pause_aria,
  );
  reflectionToggle.setAttribute("aria-pressed", reflectionManualPause ? "true" : "false");
}

function updateReflectionModeUI() {
  if (!reflectionModeToggle || !reflectionModeLabel) {
    return;
  }
  const random = reflectionPlaybackMode === "random";
  const dict = i18n[currentLanguage];
  reflectionModeToggle.dataset.reflectionMode = random ? "random" : "sequential";
  reflectionModeToggle.setAttribute("aria-pressed", random ? "true" : "false");
  reflectionModeToggle.setAttribute(
    "aria-label",
    random ? dict.reflections_mode_to_sequential : dict.reflections_mode_to_random,
  );
  reflectionModeToggle.disabled = reflectionCanonicalEntries.length < 2;
  reflectionModeLabel.textContent = random
    ? dict.reflections_mode_random
    : dict.reflections_mode_sequential;
}

function scheduleReflectionTimer() {
  clearReflectionTimer();
  syncReflectionFocusReason();
  if (!reflectionReady || reflectionEntries.length < 2 || reflectionPauseReasons.size > 0) {
    return;
  }
  reflectionDeadline = performance.now() + reflectionRemaining;
  reflectionTimer = window.setTimeout(() => {
    reflectionTimer = 0;
    advanceReflection(1, { animate: true, resetCycle: true });
  }, reflectionRemaining);
}

function restartReflectionProgress() {
  if (!reflectionRotator) {
    return;
  }
  reflectionRotator.classList.remove("is-running");
  if (reflectionEntries.length > 1) {
    void reflectionRotator.offsetWidth;
    reflectionRotator.classList.add("is-running");
  }
}

function restartReflectionCycle() {
  clearReflectionTimer();
  reflectionRemaining = REFLECTION_INTERVAL;
  restartReflectionProgress();
  scheduleReflectionTimer();
}

function pauseReflections(reason) {
  if (reflectionPauseReasons.has(reason)) {
    return;
  }
  if (reflectionPauseReasons.size === 0 && reflectionTimer) {
    reflectionRemaining = Math.max(120, reflectionDeadline - performance.now());
  }
  reflectionPauseReasons.add(reason);
  clearReflectionTimer();
  updateReflectionPauseUI();
}

function resumeReflections(reason) {
  if (!reflectionPauseReasons.delete(reason)) {
    return;
  }
  updateReflectionPauseUI();
  if (reflectionPauseReasons.size === 0) {
    scheduleReflectionTimer();
  }
}

function renderReflection({ animate = false } = {}) {
  const entry = reflectionEntries[reflectionIndex];
  if (
    !entry
    || !reflectionStage
    || !reflectionDate
    || !reflectionPreview
    || !reflectionCurrent
    || !reflectionCount
    || !reflectionMore
  ) {
    return;
  }

  const countWidth = Math.max(2, String(reflectionEntries.length).length);
  reflectionCurrent.textContent = String(reflectionIndex + 1).padStart(countWidth, "0");
  reflectionCount.textContent = String(reflectionEntries.length).padStart(countWidth, "0");
  if (reflectionEntrySource) {
    reflectionEntrySource.textContent = formatReflectionSource(entry.source);
  }
  if (entry.date) {
    reflectionDate.dateTime = entry.date;
  } else {
    reflectionDate.removeAttribute("datetime");
  }
  reflectionDate.hidden = !entry.date;
  reflectionDate.textContent = formatReflectionDate(entry.date);
  const preview = buildReflectionPreview(entry.text);
  reflectionStage.dataset.reflectionDensity = preview.density;
  reflectionStage.classList.toggle("is-truncated", preview.truncated);
  reflectionPreview.textContent = preview.text;
  reflectionPreview.lang = currentLanguage === "zh" ? "zh-CN" : "en";
  reflectionMore.hidden = !preview.truncated;
  const readAction = formatReflectionReadAction(preview.readingMinutes);
  reflectionMore.textContent = readAction;
  reflectionMore.setAttribute("aria-label", formatReflectionReadAction(preview.readingMinutes, false));

  const controlsDisabled = reflectionEntries.length < 2;
  if (reflectionPrevious) {
    reflectionPrevious.disabled = controlsDisabled;
  }
  if (reflectionNext) {
    reflectionNext.disabled = controlsDisabled;
  }
  if (reflectionToggle) {
    reflectionToggle.disabled = controlsDisabled;
  }
  if (reflectionModeToggle) {
    reflectionModeToggle.disabled = controlsDisabled;
  }

  reflectionStage.classList.remove("is-switching");
  if (animate && motionAllowed) {
    void reflectionStage.offsetWidth;
    reflectionStage.classList.add("is-switching");
  }
}

function showReflection(nextIndex, { animate = false, resetCycle = true } = {}) {
  if (!reflectionEntries.length) {
    return;
  }
  reflectionIndex = (nextIndex + reflectionEntries.length) % reflectionEntries.length;
  renderReflection({ animate });
  if (resetCycle) {
    restartReflectionCycle();
  }
}

function advanceReflection(offset, options = {}) {
  if (!reflectionEntries.length) {
    return;
  }
  if (
    reflectionPlaybackMode === "random"
    && offset > 0
    && reflectionIndex + offset >= reflectionEntries.length
  ) {
    const currentEntry = reflectionEntries[reflectionIndex];
    reflectionEntries = buildReflectionPlayback(reflectionCanonicalEntries, currentEntry);
    showReflection(0, options);
    return;
  }
  showReflection(reflectionIndex + offset, options);
}

function setReflectionPlaybackMode(mode) {
  const nextMode = mode === "sequential" ? "sequential" : "random";
  if (nextMode === reflectionPlaybackMode) {
    updateReflectionModeUI();
    return;
  }
  reflectionPlaybackMode = nextMode;
  reflectionEntries = buildReflectionPlayback(reflectionCanonicalEntries);
  reflectionIndex = 0;
  renderReflection({ animate: true });
  updateReflectionModeUI();
  restartReflectionCycle();
}

function setReflectionArchive(value) {
  const fallback = DEFAULT_REFLECTION_ARCHIVES[currentLanguage];
  const parsed = parseReflectionArchive(value);
  const selected = isValidManagedReflectionArchive(parsed, currentLanguage)
    ? parsed
    : parseReflectionArchive(fallback);
  reflectionCanonicalEntries = sortReflectionEntries(selected);
  reflectionEntries = buildReflectionPlayback(reflectionCanonicalEntries);
  reflectionIndex = 0;
  renderReflection();
  updateReflectionModeUI();
  restartReflectionCycle();
  updateReflectionPauseUI();
}

function openReflectionDialog() {
  const entry = reflectionEntries[reflectionIndex];
  if (!entry || !reflectionDialog || !reflectionDialogDate || !reflectionFullText) {
    return;
  }

  reflectionDialog.dataset.reflectionDensity = reflectionStage?.dataset.reflectionDensity || "medium";

  if (entry.date) {
    reflectionDialogDate.dateTime = entry.date;
  } else {
    reflectionDialogDate.removeAttribute("datetime");
  }
  reflectionDialogDate.hidden = !entry.date;
  reflectionDialogDate.textContent = formatReflectionDate(entry.date);
  if (reflectionDialogSource) {
    reflectionDialogSource.textContent = formatReflectionSource(entry.source);
  }
  const paragraphs = entry.text.split(/\n{2,}/).map((part) => part.trim()).filter(Boolean);
  reflectionFullText.replaceChildren(...paragraphs.map((text) => {
    const paragraph = document.createElement("p");
    paragraph.textContent = text;
    paragraph.lang = currentLanguage === "zh" ? "zh-CN" : "en";
    return paragraph;
  }));
  pauseReflections("dialog");
  reflectionDialog.showModal();
  reflectionClose?.focus();
}

function setupReflectionRotator() {
  if (!reflectionRotator || !reflectionStage) {
    return;
  }
  reflectionReady = true;
  reflectionRotator.style.setProperty("--reflection-interval", `${REFLECTION_INTERVAL}ms`);

  if (typeof ResizeObserver === "function") {
    reflectionStageWidth = Math.round(reflectionStage.getBoundingClientRect().width);
    reflectionResizeObserver = new ResizeObserver(([entry]) => {
      const width = Math.round(entry?.contentRect.width || 0);
      if (!width || Math.abs(width - reflectionStageWidth) <= 1) {
        return;
      }
      reflectionStageWidth = width;
      window.cancelAnimationFrame(reflectionResizeFrame);
      reflectionResizeFrame = window.requestAnimationFrame(() => renderReflection());
    });
    reflectionResizeObserver.observe(reflectionStage);
  }

  if (typeof IntersectionObserver === "function") {
    reflectionVisibilityObserver = new IntersectionObserver(([entry]) => {
      if (entry?.isIntersecting && entry.intersectionRatio >= 0.25) {
        resumeReflections("out-of-view");
      } else {
        pauseReflections("out-of-view");
      }
    }, { threshold: [0, 0.25] });
    reflectionVisibilityObserver.observe(reflectionStage);
  }

  reflectionRotator.addEventListener("pointerenter", () => pauseReflections("pointer"));
  reflectionRotator.addEventListener("pointerleave", () => resumeReflections("pointer"));
  reflectionRotator.addEventListener("focusin", () => pauseReflections("focus"));
  reflectionRotator.addEventListener("focusout", () => {
    window.setTimeout(scheduleReflectionTimer, 0);
  });

  reflectionPrevious?.addEventListener("click", () => {
    advanceReflection(-1, { animate: true, resetCycle: true });
  });
  reflectionNext?.addEventListener("click", () => {
    advanceReflection(1, { animate: true, resetCycle: true });
  });
  reflectionModeToggle?.addEventListener("click", () => {
    setReflectionPlaybackMode(reflectionPlaybackMode === "random" ? "sequential" : "random");
  });
  reflectionToggle?.addEventListener("click", () => {
    reflectionManualPause = !reflectionManualPause;
    if (reflectionManualPause) {
      pauseReflections("manual");
    } else {
      resumeReflections("manual");
    }
    updateReflectionPauseUI();
  });
  reflectionMore?.addEventListener("click", openReflectionDialog);
  reflectionClose?.addEventListener("click", () => reflectionDialog?.close());
  reflectionDialog?.addEventListener("close", () => resumeReflections("dialog"));
  reflectionDialog?.addEventListener("click", (event) => {
    if (event.target === reflectionDialog) {
      reflectionDialog.close();
    }
  });
  document.addEventListener("visibilitychange", () => {
    if (document.hidden) {
      pauseReflections("visibility");
    } else {
      resumeReflections("visibility");
    }
  });
  window.addEventListener("pageshow", () => {
    window.setTimeout(scheduleReflectionTimer, 0);
  });

  setReflectionArchive(i18n[currentLanguage].hero_lead);
}

function normalizeSiteContent(value) {
  if (!value || typeof value !== "object" || value.schema_version !== CONTENT_SCHEMA_VERSION) {
    return null;
  }
  if (!value.modules || typeof value.modules !== "object" || !value.copy || typeof value.copy !== "object") {
    return null;
  }

  const modules = {};
  for (const moduleId of CONTENT_MODULE_IDS) {
    const moduleState = value.modules[moduleId];
    if (!moduleState || typeof moduleState !== "object" || typeof moduleState.enabled !== "boolean") {
      return null;
    }
    modules[moduleId] = { enabled: moduleId === "site" ? true : moduleState.enabled };
  }

  const copy = {};
  for (const key of EDITABLE_CONTENT_KEYS) {
    const bilingual = value.copy[key];
    if (
      !bilingual
      || typeof bilingual !== "object"
      || typeof bilingual.zh !== "string"
      || typeof bilingual.en !== "string"
    ) {
      return null;
    }
    const zh = bilingual.zh.replace(/\r\n?/g, "\n").trim();
    const en = bilingual.en.replace(/\r\n?/g, "\n").trim();
    const maxLength = EDITABLE_CONTENT_LIMITS[key];
    if (
      !zh
      || !en
      || !Number.isInteger(maxLength)
      || reflectionTextLength(zh) > maxLength
      || reflectionTextLength(en) > maxLength
      || BANNED_CONTENT_CONTROL_PATTERN.test(zh)
      || BANNED_CONTENT_CONTROL_PATTERN.test(en)
      || (!MULTILINE_CONTENT_KEYS.has(key) && (/[\n\t]/u.test(zh) || /[\n\t]/u.test(en)))
    ) {
      return null;
    }
    copy[key] = { zh, en };
  }
  const chineseReflections = parseReflectionArchive(copy.hero_lead.zh);
  const englishReflections = parseReflectionArchive(copy.hero_lead.en);
  if (
    !isValidManagedReflectionArchive(chineseReflections, "zh")
    || !isValidManagedReflectionArchive(englishReflections, "en")
    || !haveMatchingReflectionOrder(chineseReflections, englishReflections)
  ) {
    return null;
  }
  return { modules, copy };
}

function applySiteContent(content) {
  for (const [key, bilingual] of Object.entries(content.copy)) {
    if (!EDITABLE_CONTENT_KEYS.has(key)) {
      continue;
    }
    i18n.zh[key] = bilingual.zh;
    i18n.en[key] = bilingual.en;
  }

  for (const moduleId of CONTENT_MODULE_IDS) {
    if (moduleId === "site") {
      continue;
    }
    const hidden = !content.modules[moduleId].enabled;
    document.querySelectorAll(`[data-module="${moduleId}"]`).forEach((element) => {
      element.hidden = hidden;
    });
    document.querySelectorAll(`[data-module-link="${moduleId}"]`).forEach((element) => {
      element.hidden = hidden;
      if (hidden) {
        element.classList.remove("is-active");
        element.removeAttribute("aria-current");
      }
    });
  }
}

async function loadSiteContent() {
  const requestId = ++siteContentRequestId;
  siteContentController?.abort();
  const controller = new AbortController();
  siteContentController = controller;
  const timeout = window.setTimeout(() => controller.abort(), CONTENT_FETCH_TIMEOUT);
  try {
    const response = await fetch(CONTENT_URL, {
      signal: controller.signal,
      cache: "no-cache",
      headers: { Accept: "application/json" },
    });
    if (!response.ok) {
      throw new Error(`Content request failed: ${response.status}`);
    }
    const normalized = normalizeSiteContent(await response.json());
    if (requestId !== siteContentRequestId || !normalized) {
      return;
    }
    applySiteContent(normalized);
  } catch (error) {
    if (error?.name !== "AbortError") {
      // Semantic HTML and the bundled dictionaries remain the complete fallback.
    }
  } finally {
    window.clearTimeout(timeout);
  }
}

